struct NavigationStackDemo: View {
    @State private var path: [Int] = {placeholderInitialPath}

    var body: some View {
        NavigationStack(path: $path) {
            List(0..<10, id: \.self) { value in
                NavigationLink("Row \(value)", value: value)
            }
            .navigationTitle("{navigationTitle}")
            .navigationBarTitleDisplayMode(.{titleDisplayMode})
            .toolbar({barHidden} ? .hidden : .automatic, for: .navigationBar)
            .toolbarBackgroundVisibility(.{barBackgroundVisibility}, for: .navigationBar)
            .navigationDestination(for: Int.self) { value in
                Text("Detail \(value)")
                    .navigationBarBackButtonHidden({backButtonHidden})
            }
        }
    }
}

struct NavigationPathDemo: View {
    @State private var path = NavigationPath()

    var body: some View {
        NavigationStack(path: $path) {
            List {
                Button("Push Int") { path.append({placeholderInt}) }
                Button("Push String") { path.append("{placeholderString}") }
                Button("Pop") { if !path.isEmpty { path.removeLast() } }
            }
            .navigationDestination(for: Int.self) { Text("Int \($0)") }
            .navigationDestination(for: String.self) { Text("String \($0)") }
            .navigationTitle("Count \(path.count)")
        }
    }
}

struct NavigationDestinationDemo: View {
    @State private var showDetail = {isPresented}

    var body: some View {
        NavigationStack {
            List {
                NavigationLink("Value link", value: 42)
                Button("Boolean push") { showDetail = true }
            }
            .navigationDestination(for: Int.self) { Text("Detail for \($0)") }
            .navigationDestination(isPresented: $showDetail) { Text("Boolean-driven detail") }
        }
    }
}

struct NavigationLinkDemo: View {
    var body: some View {
        NavigationStack {
            List {
                NavigationLink(value: "detail") {
                    Label("{label}", systemImage: "{systemImage}")
                }
                .disabled({isDisabled})
            }
            .navigationDestination(for: String.self) { Text("Detail: \($0)") }
            .navigationTitle("Links")
        }
    }
}

struct NavigationSplitViewDemo: View {
    @State private var columnVisibility = NavigationSplitViewVisibility.{columnVisibility}
    @State private var preferredColumn = NavigationSplitViewColumn.{preferredCompactColumn}
    @State private var selection: Int?

    var body: some View {
        NavigationSplitView(columnVisibility: $columnVisibility, preferredCompactColumn: $preferredColumn) {
            List(0..<8, id: \.self, selection: $selection) { Text("Item \($0)") }
                .navigationSplitViewColumnWidth({sidebarColumnWidth})
                .navigationTitle("{sidebarTitle}")
        } detail: {
            if let selection { Text("Detail \(selection)") } else { Text("Select an item") }
        }
        .navigationSplitViewStyle(.{style})
    }
}

struct ThreeColumnSplitDemo: View {
    @State private var columnVisibility = NavigationSplitViewVisibility.{columnVisibility}
    @State private var department: Int?
    @State private var employee: Int?

    var body: some View {
        NavigationSplitView(columnVisibility: $columnVisibility) {
            List(0..<4, id: \.self, selection: $department) { Text("Department \($0)") }
                .navigationTitle("Departments")
        } content: {
            List(0..<6, id: \.self, selection: $employee) { Text("Employee \($0)") }
                .navigationSplitViewColumnWidth(min: {contentColumnWidthMin}, ideal: 250)
                .navigationTitle("Employees")
        } detail: {
            if let employee { Text("Details for \(employee)") } else { Text("Select an employee") }
        }
        .navigationSplitViewStyle(.{style})
    }
}

struct TabViewDemo: View {
    @State private var selection = {selectedTab}

    var body: some View {
        TabView(selection: $selection) {
            Tab("Home", systemImage: "house", value: 0) { Text("Home") }
            Tab("Browse", systemImage: "square.grid.2x2", value: 1) { Text("Browse") }
                .badge({showBadges} ? 3 : 0)
            Tab("Profile", systemImage: "person.crop.circle", value: 2) { Text("Profile") }
            Tab(role: .search) { Text("Search") }
        }
        .tabViewStyle(.{style})
        .tabBarMinimizeBehavior(.{tabBarMinimizeBehavior})
    }
}

Tab("{title}", systemImage: "{systemImage}", value: 0) {
    Text("{title} content")
}
.badge({badge})
.customizationID("{customizationID}")

TabSection("{header}") {
    Tab("Recently Added", systemImage: "clock", value: 10) { Text("Recent") }
    Tab("Artists", systemImage: "music.mic", value: 11) { Text("Artists") }
}
.customizationID("{customizationID}")

TabView {
    Tab("Home", systemImage: "house") { Text("Home") }
    Tab("Library", systemImage: "books.vertical") { Text("Library") }
}
.tabViewBottomAccessory {
    if {enabled} {
        HStack { Image(systemName: "play.fill"); Text("{label}") }
    }
}

struct ToolbarDemo: View {
    var body: some View {
        NavigationStack {
            Text("Content")
                .navigationTitle("Toolbar")
                .toolbar {
                    ToolbarItem(placement: .{primaryPlacement}) {
                        Button("Action") {}.disabled({itemsDisabled})
                    }
                    ToolbarItemGroup(placement: .topBarTrailing) {
                        Button { } label: { Image(systemName: "square.and.arrow.up") }
                        Button { } label: { Image(systemName: "ellipsis") }
                    }
                }
        }
    }
}

ToolbarItem(placement: .{placement}) {
    Button("{label}") {}
}

ToolbarItemGroup(placement: .{placement}) {
    Button { } label: { Image(systemName: "bold") }
    Button { } label: { Image(systemName: "italic") }
    Button { } label: { Image(systemName: "underline") }
}

Text("Content")
    .toolbar {
        ToolbarItem(placement: .topBarTrailing) { Button("Tag") {} }
        ToolbarSpacer(.{sizing})
        ToolbarItem(placement: .topBarTrailing) { Button("More") {} }
    }

struct SearchableDemo: View {
    @State private var query = ""
    @State private var scope = 0

    var body: some View {
        NavigationStack {
            List(results, id: \.self) { Text($0) }
                .searchable(text: $query, placement: .{placement}, prompt: "{prompt}")
                .searchScopes($scope) {
                    Text("All").tag(0)
                    Text("Favorites").tag(1)
                }
                .searchSuggestions {
                    Text("Recent").searchCompletion("recent")
                }
        }
    }

    var results: [String] { [] }
}

struct SearchTokenDemo: View {
    struct Tag: Identifiable, Hashable { let id = UUID(); let name: String }
    @State private var query = ""
    @State private var tokens: [Tag] = [Tag(name: "swift")]

    var body: some View {
        NavigationStack {
            List { Text("Results") }
                .searchable(text: $query, tokens: $tokens, prompt: "{prompt}") { token in
                    Text(token.name)
                }
        }
    }
}

struct ZoomTransitionDemo: View {
    @Namespace private var namespace

    var body: some View {
        NavigationStack {
            NavigationLink {
                DetailView()
                    .navigationTransition(.zoom(sourceID: "{sourceID}", in: namespace))
            } label: {
                Thumbnail()
            }
            .matchedTransitionSource(id: "{sourceID}", in: namespace)
        }
    }
}

struct BackButtonDemo: View {
    @Environment(\.dismiss) private var dismiss

    var body: some View {
        Text("Detail")
            .navigationBarBackButtonHidden({backButtonHidden})
            .toolbarRole(.{toolbarRole})
            .toolbar {
                if {customBackButton} {
                    ToolbarItem(placement: .topBarLeading) {
                        Button { dismiss() } label: { Image(systemName: "chevron.backward") }
                    }
                }
            }
    }
}

struct PageTabViewDemo: View {
    var body: some View {
        TabView {
            ForEach(0..<{pageCount}, id: \.self) { index in
                Text("Page \(index)")
            }
        }
        .tabViewStyle(.page(indexDisplayMode: .{indexDisplayMode}))
        .indexViewStyle(.page(backgroundDisplayMode: .{backgroundDisplayMode}))
    }
}

NavigationSplitView {
    List(0..<8, id: \.self) { Text("Item \($0)") }
        .toolbar(removing: .{defaultItemKind})
        .navigationTitle("Sidebar")
} detail: {
    Text("Detail")
}

struct ToolbarTitleMenuDemo: View {
    var body: some View {
        NavigationStack {
            Text("Content")
                .navigationTitle("Document")
                .toolbarTitleMenu {
                    Button("Rename") {}
                    Button("Duplicate") {}
                    Button("Print") {}
                }
        }
    }
}

struct CustomizableToolbarDemo: View {
    var body: some View {
        NavigationStack {
            Text("Content")
                .toolbar(id: "main") {
                    ToolbarItem(id: "tag", placement: .secondaryAction) {
                        Button { } label: { Label("Tag", systemImage: "tag") }
                    }
                    ToolbarItem(id: "share", placement: .secondaryAction) {
                        Button { } label: { Label("Share", systemImage: "square.and.arrow.up") }
                    }
                }
        }
    }
}

struct NavigationSubtitleDemo: View {
    var body: some View {
        NavigationStack {
            List(0..<10, id: \.self) { Text("Row \($0)") }
                .navigationTitle("{title}")
                .navigationSubtitle("{subtitle}")
        }
    }
}

struct SidebarAdaptableTabDemo: View {
    @State private var customization = TabViewCustomization()

    var body: some View {
        TabView {
            Tab("Home", systemImage: "house") { Text("Home") }
                .customizationID("tab.home")
            Tab("Browse", systemImage: "square.grid.2x2") { Text("Browse") }
                .customizationID("tab.browse")
            TabSection("Library") {
                Tab("Recent", systemImage: "clock") { Text("Recent") }
                    .customizationID("tab.recent")
                Tab("Artists", systemImage: "music.mic") { Text("Artists") }
                    .customizationID("tab.artists")
            }
            .customizationID("section.library")
        }
        .tabViewStyle(.sidebarAdaptable)
        .tabViewCustomization($customization)
    }
}

NavigationView {
    List(0..<10, id: \.self) { value in
        NavigationLink("Row \(value)") { Text("Detail \(value)") }
    }
    .navigationTitle("Legacy")
}
.navigationViewStyle(.{style})
